int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_cost = 0;
    int balance = 0;

    // Min-priority queue to store {cost_to_flip_from_')'_to_'(' , index_of_question_mark}
    // The cost_to_flip is (cost_of_opening_bracket - cost_of_closing_bracket)
    // We use a min-priority queue because when balance drops below zero, we want to
    // flip a ')' to '(' that has the smallest additional cost (or largest saving).
    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, std::greater<std::pair<int, int>>> pq;

    for (int i = 0; i < s.length(); ++i) {
        if (s[i] == '(') {
            balance++;
        } else if (s[i] == ')') {
            balance--;
        } else { // s[i] == '?'
            int a_cost, b_cost; // a_cost for '(', b_cost for ')'
            std::cin >> a_cost >> b_cost;

            // Greedily assume '?' is ')' initially.
            // This helps keep the balance low and allows for more flexibility later.
            s[i] = ')';
            total_cost += b_cost;
            balance--;

            // Store the cost difference if we were to change this ')' back to '('.
            // This is (cost_if_open - cost_if_close).
            pq.push({a_cost - b_cost, i});
        }

        // If the balance drops below zero, it means we have too many ')'s.
        // We must change one of the previously chosen ')'s (from a '?') to an '('.
        if (balance < 0) {
            if (pq.empty()) {
                // If priority queue is empty, there are no '?'s that we can flip.
                // Thus, it's impossible to make the sequence regular.
                std::cout << -1 << std::endl;
                return 0;
            }

            // Pick the ')' that is cheapest to flip to '('.
            // This is the one with the minimum (a_cost - b_cost).
            std::pair<int, int> cheapest_flip = pq.top();
            pq.pop();

            total_cost += cheapest_flip.first; // Add the cost difference to total cost
            s[cheapest_flip.second] = '(';     // Change the character in the string to '('
            balance += 2;                       // Balance increases by 2 (from ')' to '(' changes balance by +2)
        }
    }

    // After processing the entire string, the balance must be zero for a regular bracket sequence.
    if (balance != 0) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << total_cost << std::endl;
        std::cout << s << std::endl;
    }

    return 0;
}
