    std::string line;
    int max_len = 0; // To store the maximum length among all input lines

    // Read all lines from input and find the maximum line length
    while (std::getline(std::cin, line)) {
        lines.push_back(line);
        if (line.length() > max_len) {
            max_len = line.length();
        }
    }

    // The frame width will be max_len + 2 (for the '*' characters on both sides)
    int frame_width = max_len + 2;

    // Print the top border of the frame
    for (int i = 0; i < frame_width; ++i) {
        std::cout << '*';
    }
    std::cout << std::endl;

    // This boolean controls the alternating bias for odd padding.
    // true means the next odd padding should have more spaces on the right (closer left).
    // false means the next odd padding should have more spaces on the left (closer right).
    bool left_bias_next = true;

    // Process each line for alignment and print it within the frame
    for (const std::string& current_line : lines) {
        int padding = max_len - current_line.length();
        int left_padding, right_padding;

        if (padding % 2 == 0) {
            // If padding is even, distribute spaces equally on both sides
            left_padding = padding / 2;
            right_padding = padding / 2;
        } else {
            // If padding is odd, apply alternating bias
            if (left_bias_next) {
                // "Bringing them closer left": fewer spaces on the left
                left_padding = padding / 2;
                right_padding = padding / 2 + 1;
            } else {
                // "Bringing them closer right": fewer spaces on the right
                left_padding = padding / 2 + 1;
                right_padding = padding / 2;
            }
            // Toggle the bias for the next odd padding line
            left_bias_next = !left_bias_next;
        }

        // Print the framed and aligned line
        std::cout << '*';
        for (int i = 0; i < left_padding; ++i) {
            std::cout << ' ';
        }
        std::cout << current_line;
        for (int i = 0; i < right_padding; ++i) {
            std::cout << ' ';
        }
        std::cout << '*' << std::endl;
    }

    // Print the bottom border of the frame
    for (int i = 0; i < frame_width; ++i) {
        std::cout << '*';
    }
    std::cout << std::endl;

    return 0;
}
