int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    std::stack<int> st;
    st.push(-1); // Push a sentinel value to the stack.
                 // This helps in calculating lengths: i - st.top() will give correct length
                 // even if the sequence starts from index 0.

    int max_len = 0; // Stores the maximum length found so far
    int count = 1;   // Stores the number of substrings with max_len.
                     // Initialized to 1 for the "0 1" case (no regular bracket sequences).

    for (int i = 0; i < s.length(); ++i) {
        if (s[i] == '(') {
            st.push(i); // Push the index of an opening bracket
        } else { // s[i] == ')'
            st.pop(); // Try to match with the most recent opening bracket

            if (st.empty()) {
                // If the stack becomes empty, it means the current ')' is unmatched.
                // This ')' effectively breaks any potential regular bracket sequence
                // that could have extended past it. So, we push its index as a new
                // sentinel, marking the start of a new potential sequence.
                st.push(i);
            } else {
                // If the stack is not empty, we successfully matched a pair.
                // The length of the current valid regular bracket sequence ending at 'i'
                // is 'i - st.top()'. 'st.top()' is the index of the unmatched opening
                // bracket *before* the current valid sequence, or the sentinel -1.
                int current_len = i - st.top();

                if (current_len > max_len) {
                    max_len = current_len;
                    count = 1; // Reset count as we found a new maximum length
                } else if (current_len == max_len) {
                    count++; // Increment count if we found another sequence of the same max length
                }
            }
        }
    }

    // Output the maximum length and the count of such substrings
    std::cout << max_len << " " << count << std::endl;

    return 0;
}
