    // For a non-degenerate triangle, a + b > c must hold.
    // For a degenerate triangle, a + b == c must hold.
    // Since sticks are sorted, we only need to check the largest side against the sum of the two smaller ones.

    // Combinations of 3 sticks from sorted array sticks[0], sticks[1], sticks[2], sticks[3]:
    // 1. (sticks[0], sticks[1], sticks[2])
    // 2. (sticks[0], sticks[1], sticks[3])
    // 3. (sticks[0], sticks[2], sticks[3])
    // 4. (sticks[1], sticks[2], sticks[3])

    // Check for non-degenerate triangle
    if (sticks[0] + sticks[1] > sticks[2]) found_triangle = true;
    if (sticks[0] + sticks[1] > sticks[3]) found_triangle = true;
    if (sticks[0] + sticks[2] > sticks[3]) found_triangle = true;
    if (sticks[1] + sticks[2] > sticks[3]) found_triangle = true;

    if (found_triangle) {
        std::cout << "TRIANGLE" << std::endl;
        return;
    }

    // If no non-degenerate triangle, check for degenerate triangle
    if (sticks[0] + sticks[1] == sticks[2]) found_segment = true;
    if (sticks[0] + sticks[1] == sticks[3]) found_segment = true;
    if (sticks[0] + sticks[2] == sticks[3]) found_segment = true;
    if (sticks[1] + sticks[2] == sticks[3]) found_segment = true;

