    std::cin >> n >> k;

    std::vector<int> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::multiset<int> window_heights;
    int left = 0;
    int max_len = 0;
    std::vector<std::pair<int, int>> results;

    for (int right = 0; right < n; ++right) {
        window_heights.insert(h[right]);

        // Shrink the window from the left if the height difference exceeds k
        while (*window_heights.rbegin() - *window_heights.begin() > k) {
            // Remove the element at the left pointer from the multiset
            // std::multiset::erase(value) removes all occurrences of value.
            // We need to remove only one occurrence, so use find() to get an iterator.
            window_heights.erase(window_heights.find(h[left]));
            left++;
        }

        // The current window [left, right] is valid
        int current_len = right - left + 1;
        if (current_len > max_len) {
            max_len = current_len;
            results.clear(); // Found a new maximum length, clear previous results
            results.push_back({left + 1, right + 1}); // Store 1-based indices
        } else if (current_len == max_len) {
            results.push_back({left + 1, right + 1}); // Add to results if length is equal to max_len
        }
    }

    std::cout << max_len << " " << results.size() << std::endl;
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << std::endl;
