// Extended Euclidean Algorithm:
// Returns {gcd(a, b), x, y} such that a*x + b*y = gcd(a, b)
// This implementation correctly handles negative a, b.
std::tuple<long long, long long, long long> extended_gcd(long long a, long long b) {
    if (a == 0) {
        return {b, 0, 1};
    }
    auto [g, x1, y1] = extended_gcd(b % a, a);
    long long x = y1 - (b / a) * x1;
    long long y = x1;
    return {g, x, y};
}

void solve_2_7_C_Line() {
    long long A, B, C;
    std::cin >> A >> B >> C;

    // Handle special cases where A or B is zero
    // Problem guarantees A^2 + B^2 > 0, so A and B are not both zero.
    if (A == 0) {
        // Equation becomes By + C = 0 => By = -C
        if ((-C) % B == 0) {
            long long y = (-C) / B;
            // x can be any integer, we choose 0.
            // The value of y will be within [-2*10^9, 2*10^9] / 1 = [-2*10^9, 2*10^9],
            // which is well within the required [-5*10^18, 5*10^18] range.
            std::cout << 0 << " " << y << std::endl;
        } else {
            std::cout << -1 << std::endl; // No integer solution for y
        }
        return;
    }

    if (B == 0) {
        // Equation becomes Ax + C = 0 => Ax = -C
        if ((-C) % A == 0) {
            long long x = (-C) / A;
            // y can be any integer, we choose 0.
            // The value of x will be within [-2*10^9, 2*10^9],
            // which is well within the required [-5*10^18, 5*10^18] range.
            std::cout << x << " " << 0 << std::endl;
        } else {
            std::cout << -1 << std::endl; // No integer solution for x
        }
        return;
    }

    // Both A and B are non-zero. We need to solve Ax + By = -C.
    // This is a linear Diophantine equation.
    // First, find gcd(A, B). std::gcd returns a non-negative value.
    long long common_divisor = std::gcd(A, B);

    // A solution exists if and only if -C is divisible by gcd(A, B).
    if ((-C) % common_divisor != 0) {
        std::cout << -1 << std::endl;
        return;
    }

    // Find a particular solution (x_g, y_g) for A*x_g + B*y_g = common_divisor
    auto [g, x_g, y_g] = extended_gcd(A, B);

    // Scale the particular solution to match the target constant -C.
    // The multiplier is (-C) / common_divisor.
    long long multiplier = (-C) / common_divisor;
    long long x = x_g * multiplier;
    long long y = y_g * multiplier;

    // The values x_g and y_g returned by extended_gcd are typically bounded by |B|/g and |A|/g respectively.
    // The multiplier is bounded by |C|/g.
    // So, x can be roughly (|B|/g) * (|C|/g). Max values: (2e9/1) * (2e9/1) = 4e18.
    // This fits within the required range of [-5*10^18, 5*10^18].
    // Thus, the first particular solution found is guaranteed to be within the range.
    std::cout << x << " " << y << std::endl;
}
