        for (int i = 0; i < n; ++i) {
            // If object 'i' (0-indexed) is not yet collected
            if (!(mask & (1 << i))) {
                // Option 1: Pick up object 'i' alone
                int new_mask_1 = mask | (1 << i);
                // Cost: travel from handbag to object 'i', then from object 'i' back to handbag
                long long cost_1 = dist_sq(all_points[0], all_points[i + 1]) + dist_sq(all_points[i + 1], all_points[0]);

                if (dp[mask] + cost_1 < dp[new_mask_1]) {
                    dp[new_mask_1] = dp[mask] + cost_1;
                    parent[new_mask_1] = {mask, i + 1, -1}; // Store 1-based index for object 'i', -1 for no second object
                }

                // Option 2: Pick up object 'i' and another uncollected object 'j'
                // Iterate 'j' from 'i+1' to avoid duplicate pairs (i,j) and (j,i)
                for (int j = i + 1; j < n; ++j) {
                    // If object 'j' (0-indexed) is also not yet collected
                    if (!(mask & (1 << j))) {
                        int new_mask_2 = mask | (1 << i) | (1 << j);
                        // Cost: handbag -> object 'i' -> object 'j' -> handbag
                        long long cost_2 = dist_sq(all_points[0], all_points[i + 1]) +
                                           dist_sq(all_points[i + 1], all_points[j + 1]) +
                                           dist_sq(all_points[j + 1], all_points[0]);

                        if (dp[mask] + cost_2 < dp[new_mask_2]) {
                            dp[new_mask_2] = dp[mask] + cost_2;
                            parent[new_mask_2] = {mask, i + 1, j + 1}; // Store 1-based indices for objects 'i' and 'j'
                        }
                    }
                }
            }
        }
    }

    // The minimum time is stored in dp[(1 << n) - 1], which represents all objects collected.
    std::cout << dp[(1 << n) - 1] << std::endl;

    // Path reconstruction
    std::vector<int> result_path;
    int current_mask = (1 << n) - 1; // Start from the final state (all objects collected)
    result_path.push_back(0); // The path always starts at the handbag (index 0)

    while (current_mask != 0) {
        ParentInfo info = parent[current_mask];
        if (info.obj2 == -1) { // If only one object was picked in this step
            result_path.push_back(info.obj1); // Go to object 1
            result_path.push_back(0);         // Return to handbag
        } else { // If two objects were picked in this step
            result_path.push_back(info.obj1); // Go to object 1
            result_path.push_back(info.obj2); // Then to object 2
            result_path.push_back(0);         // Return to handbag
        }
        current_mask = info.prev_mask; // Move to the previous mask state
    }

    // Print the reconstructed path
    for (size_t i = 0; i < result_path.size(); ++i) {
        std::cout << result_path[i] << (i == result_path.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;
}
