int block_size_global;

// Function to recompute values for a specific block
void recompute_block(int block_idx) {
    int block_start = block_idx * block_size_global;
    int block_end = std::min(N_global - 1, (block_idx + 1) * block_size_global - 1);

    // Iterate backwards through the block to correctly compute dependencies
    for (int i = block_end; i >= block_start; --i) {
        int target = i + A_global[i];
        if (target >= N_global || (target / block_size_global) != block_idx) {
            // Target is out of bounds or in a different block
            next_block_jump_global[i] = target;
            jumps_count_global[i] = 1;
            last_visited_in_block_global[i] = i;
        } else {
            // Target is in the same block, use precomputed values for target
            next_block_jump_global[i] = next_block_jump_global[target];
            jumps_count_global[i] = 1 + jumps_count_global[target];
            last_visited_in_block_global[i] = last_visited_in_block_global[target];
        }
    }
}

int main() {
