int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<std::vector<std::pair<int, int>>> adj(n + 1);
    for (int i = 0; i < m; ++i) {
        int u, v, w;
        std::cin >> u >> v >> w;
        adj[u].push_back({v, w});
        adj[v].push_back({u, w});
    }

    std::vector<long long> dist(n + 1, INF);
    std::vector<int> parent(n + 1, 0); // To reconstruct path

    // Priority queue stores pairs of {distance, vertex}
    // std::greater makes it a min-priority queue
    std::priority_queue<std::pair<long long, int>,
                        std::vector<std::pair<long long, int>>,
                        std::greater<std::pair<long long, int>>> pq;

    dist[1] = 0;
    pq.push({0, 1});

    while (!pq.empty()) {
        long long d = pq.top().first;
        int u = pq.top().second;
        pq.pop();

        // If we found a shorter path to u already, skip
        if (d > dist[u]) {
            continue;
        }

        // Explore neighbors
        for (auto& edge : adj[u]) {
            int v = edge.first;
            int weight = edge.second;

            if (dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                parent[v] = u; // Set u as parent of v
                pq.push({dist[v], v});
            }
        }
    }

    // Path reconstruction
    if (dist[n] == INF) {
        std::cout << -1 << std::endl;
    } else {
        std::vector<int> path;
        int curr = n;
        while (curr != 0) { // Backtrack from n to 1 using parent array
            path.push_back(curr);
            curr = parent[curr];
        }
        std::reverse(path.begin(), path.end()); // Path is built in reverse order

        for (size_t i = 0; i < path.size(); ++i) {
            std::cout << path[i] << (i == path.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}
