    if (total_sum % 3 != 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    long long target_sum = total_sum / 3;
    long long current_sum = 0;
    long long count_first_part_sum = 0; // Counts ways to make the first piece sum to target_sum
    long long ans = 0;

    // Iterate through possible second cut points (exclusive end index of the second piece)
    // The second cut is after index j, so the second piece is a[i+1...j].
    // The prefix sum P[k] is sum of a[0...k-1].
    // We are looking for P[k] == 2*target_sum, where k is the end of the second piece + 1.
    // The loop variable 'k' here represents the length of the prefix sum.
    // k goes from 1 to n-1.
    // If k=1, P[1] is a[0]. This can be the first piece.
    // If k=n-1, P[n-1] is a[0...n-2]. This can be the first two pieces.
    for (int k = 0; k < n - 1; ++k) { // k is the index of the element being added to current_sum
        current_sum += a[k];

        // If current_sum is 2*target_sum, it means we found a potential end for the second piece.
        // The number of ways to form the first piece (ending before this point) is count_first_part_sum.
        // This ensures the first piece ends before the second piece.
        if (current_sum == 2 * target_sum) {
            ans += count_first_part_sum;
        }

        // If current_sum is target_sum, it means we found a potential end for the first piece.
        // Increment the counter for future second piece calculations.
        if (current_sum == target_sum) {
            count_first_part_sum++;
        }
    }

    std::cout << ans << std::endl;

    return 0;
