// f[i] stores the person that person i calls
std::vector<int> f;
// visited_state: 0 = unvisited, 1 = visiting (on current path/recursion stack), 2 = visited (processed)
std::vector<int> visited_state;
// unique_cycle_representatives: stores one node from each distinct cycle found
std::set<int> unique_cycle_representatives;

// Iterative DFS to find cycles and mark nodes' visited states
void find_cycles_and_mark_nodes(int start_node) {
    std::stack<int> path_stack;
    int curr = start_node;

    // Traverse until we hit a visited node
    while (visited_state[curr] == 0) {
        visited_state[curr] = 1; // Mark as visiting
        path_stack.push(curr);
        curr = f[curr];
    }

    // If we hit a node that is currently being visited (state 1), it means we found a cycle.
    if (visited_state[curr] == 1) {
        unique_cycle_representatives.insert(curr);
        // Nodes from 'curr' up to path_stack.top() (inclusive) form the cycle.
        // We don't need to explicitly mark 'is_cycle_node' for this problem,
        // as we only care about the count of distinct cycles and nodes with in-degree 0.
    }

    // Mark all nodes on the current path_stack as fully processed (visited_state=2).
    // These nodes are either part of a cycle (if visited_state[curr] was 1)
    // or part of a tree leading to an already processed component/cycle (if visited_state[curr] was 2).
    while (!path_stack.empty()) {
        visited_state[path_stack.top()] = 2;
        path_stack.pop();
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    f.resize(n + 1);
    std::vector<int> in_degree(n + 1, 0);
    for (int i = 1; i <= n; ++i) {
        std::cin >> f[i];
        in_degree[f[i]]++;
    }

    // Identify nodes with in-degree 0. These are "roots" of trees that need incoming connections.
    std::vector<int> roots_with_zero_in_degree;
    for (int i = 1; i <= n; ++i) {
        if (in_degree[i] == 0) {
            roots_with_zero_in_degree.push_back(i);
        }
    }

    visited_state.assign(n + 1, 0); // Initialize all nodes as unvisited

    // Find all distinct cycles in the graph
    for (int i = 1; i <= n; ++i) {
        if (visited_state[i] == 0) {
            find_cycles_and_mark_nodes(i);
        }
    }

    // Convert set of cycle representatives to a vector for indexed access
    std::vector<int> cycle_representatives_vec(unique_cycle_representatives.begin(), unique_cycle_representatives.end());

    // Calculate the minimum number of edges to add
    // 1. Each node with in-degree 0 needs an incoming edge. This accounts for `roots_with_zero_in_degree.size()` edges.
    // 2. If there are multiple cycles, they need to be connected into a single large cycle. This takes `num_cycles - 1` edges.
    //    (e.g., to connect k cycles, you need k edges to form a cycle of cycles, but one edge is already part of the original graph, so k-1 additional edges).
    //    If there's only one cycle, 0 additional edges are needed for this part.
    int num_edges_to_add = roots_with_zero_in_degree.size();
    if (cycle_representatives_vec.size() > 1) {
        num_edges_to_add += (cycle_representatives_vec.size() - 1);
    }

    std::cout << num_edges_to_add << "\n";

    std::vector<std::pair<int, int>> added_edges;

    // Strategy for adding edges:
    // 1. Connect all nodes with in-degree 0 to one of the cycle representatives.
    //    Since N >= 2, there will always be at least one cycle, so cycle_representatives_vec will not be empty.
    int cycle_source_for_roots = cycle_representatives_vec[0];
    for (int root_node : roots_with_zero_in_degree) {
        added_edges.push_back({cycle_source_for_roots, root_node});
    }

    // 2. Connect the cycle representatives into a single large cycle.
    if (cycle_representatives_vec.size() > 1) {
        for (size_t i = 0; i < cycle_representatives_vec.size() - 1; ++i) {
            added_edges.push_back({cycle_representatives_vec[i], cycle_representatives_vec[i+1]});
        }
        // Connect the last cycle representative back to the first one
        added_edges.push_back({cycle_representatives_vec.back(), cycle_representatives_vec[0]});
    }

    // Output the added edges
    for (const auto& edge : added_edges) {
